class Solution:
    def nthMagicalNumber(self, n, a, b):
        import math
        MOD = 10 ** 9 + 7
        l = a * b // math.gcd(a, b)
        lo, hi = 1, n * min(a, b)
        while lo < hi:
            mid = (lo + hi) // 2
            cnt = mid // a + mid // b - mid // l
            if cnt >= n:
                hi = mid
            else:
                lo = mid + 1
        return lo % MOD

