var nthMagicalNumber = function(n, a, b) {
    const MOD = 1000000007n;
    const gcd = (x, y) => { while (y) { [x, y] = [y, x % y]; } return x; };
    const A = BigInt(a), B = BigInt(b), N = BigInt(n);
    const L = A * B / gcd(A, B);
    let lo = 1n, hi = N * (A < B ? A : B);
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        const cnt = mid / A + mid / B - mid / L;
        if (cnt >= N) hi = mid; else lo = mid + 1n;
    }
    return Number(lo % MOD);
};
